const STORAGE_KEY = "notepad-content";

export function loadContent() {
    return localStorage.getItem(STORAGE_KEY) ?? "";
}

export function saveContent(content) {
    localStorage.setItem(STORAGE_KEY, content);
}

export function clearContent() {
    localStorage.removeItem(STORAGE_KEY);
}

let beforeUnloadHandler = null;

export function enableBeforeUnload() {
    if (!beforeUnloadHandler) {
        beforeUnloadHandler = (e) => {
            e.preventDefault();
            e.returnValue = "";
        };
        window.addEventListener("beforeunload", beforeUnloadHandler);
    }
}

export function disableBeforeUnload() {
    if (beforeUnloadHandler) {
        window.removeEventListener("beforeunload", beforeUnloadHandler);
        beforeUnloadHandler = null;
    }
}

@page "/notepad"
@rendermode InteractiveServer
@implements IAsyncDisposable
@inject IJSRuntime JS

<PageTitle>Notepad</PageTitle>

<h1>Notepad</h1>

<div class="mb-3">
    <textarea class="form-control" rows="12" @bind="content" @bind:event="oninput" placeholder="Type your notes here..."></textarea>
</div>

<div class="d-flex align-items-center gap-3">
    <button class="btn btn-primary" @onclick="SaveNow">Save now</button>
    <button class="btn btn-outline-danger" @onclick="Clear">Clear</button>
    @if (lastSavedAt is not null)
    {
        <span class="text-muted">Last saved at @lastSavedAt.Value.ToString("HH:mm:ss")</span>
    }
</div>

@code {
    private string content = "";
    private string lastSavedContent = "";
    private DateTime? lastSavedAt;
    private IJSObjectReference? module;
    private System.Threading.Timer? autoSaveTimer;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            module = await JS.InvokeAsync<IJSObjectReference>(
                "import", $"./{@Assets["Components/Pages/Notepad.razor.js"]}");

            content = await module.InvokeAsync<string>("loadContent");
            lastSavedContent = content;

            autoSaveTimer = new System.Threading.Timer(async _ =>
            {
                await InvokeAsync(AutoSave);
            }, null, TimeSpan.FromSeconds(30), TimeSpan.FromSeconds(30));

            StateHasChanged();
        }
    }

    private bool HasUnsavedChanges => content != lastSavedContent;

    private async Task AutoSave()
    {
        if (HasUnsavedChanges)
        {
            await SaveContent();
            StateHasChanged();
        }
    }

    private async Task SaveNow()
    {
        await SaveContent();
    }

    private async Task SaveContent()
    {
        if (module is null) return;

        await module.InvokeVoidAsync("saveContent", content);
        lastSavedContent = content;
        lastSavedAt = DateTime.Now;
        await module.InvokeVoidAsync("disableBeforeUnload");
    }

    private async Task Clear()
    {
        if (module is null) return;

        content = "";
        lastSavedContent = "";
        lastSavedAt = null;
        await module.InvokeVoidAsync("clearContent");
        await module.InvokeVoidAsync("disableBeforeUnload");
    }

    private async Task UpdateBeforeUnload()
    {
        if (module is null) return;

        if (HasUnsavedChanges)
            await module.InvokeVoidAsync("enableBeforeUnload");
        else
            await module.InvokeVoidAsync("disableBeforeUnload");
    }

    // Called by @bind on every input change
    private string Content
    {
        get => content;
        set
        {
            content = value;
            _ = UpdateBeforeUnload();
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (autoSaveTimer is not null)
            await autoSaveTimer.DisposeAsync();

        if (module is not null)
        {
            await module.InvokeVoidAsync("disableBeforeUnload");
            await module.DisposeAsync();
        }
    }
}

